import { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { useMutation } from '@tanstack/react-query';
import { z } from 'zod';
import { Loader2, Mail, CheckCircle2 } from 'lucide-react';
import { authService as accountService } from '@/api/auth/authService';
import { getApiErrorMessage, getApiErrorStatus } from '@/api/app/apiError';
import { ROUTES } from '@/lib/routes';

import { AuthLayout } from '../layouts/AuthLayout';
import { HarmonyInput } from '@/components/ui/harmony-input';
import { Button } from '@/shadcn/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/shadcn/components/ui/card';
import { Alert, AlertDescription } from '@/shadcn/components/ui/alert';

const forgotSchema = z.object({
  email: z.string().min(1, 'Email is required').email('Invalid email address').trim(),
});

type ForgotFormData = z.infer<typeof forgotSchema>;

export default function ForgotPassword() {
  const navigate = useNavigate();
  const [isSubmitted, setIsSubmitted] = useState(false);
  const [serverError, setServerError] = useState<string | null>(null);

  const { register, handleSubmit, formState: { errors } } = useForm<ForgotFormData>({
    resolver: zodResolver(forgotSchema),
  });

  useEffect(() => {
    if (!isSubmitted) return;
    const t = setTimeout(() => navigate(ROUTES.LOGIN), 3000);
    return () => clearTimeout(t);
  }, [isSubmitted, navigate]);

  const mutation = useMutation({
    mutationFn: (data: ForgotFormData) => accountService.forgotPassword(data.email),
    onSuccess: () => {
      setIsSubmitted(true);
    },
    onError: (error) => {
      if (getApiErrorStatus(error) === 404) {
        setServerError('No account found with that email address.');
      } else {
        setServerError(getApiErrorMessage(error));
      }
    },
  });

  return (
    <AuthLayout>
      <Card className="py-8 gap-8">
        {!isSubmitted ? (
          <>
            <CardHeader>
              <CardTitle className="text-2xl font-semibold tracking-tight">Reset password</CardTitle>
              <CardDescription>Enter your email and we'll send you reset instructions.</CardDescription>
            </CardHeader>
            <CardContent className="space-y-5">
              {serverError && (
                <Alert variant="destructive">
                  <AlertDescription>{serverError}</AlertDescription>
                </Alert>
              )}
              <form
                onSubmit={handleSubmit((data) => { setServerError(null); mutation.mutate(data); })}
                className="space-y-5"
              >
                <HarmonyInput
                  label="Email"
                  type="email"
                  placeholder="name@company.com"
                  leftIcon={<Mail size={16} />}
                  error={errors.email?.message}
                  {...register('email')}
                />
                <Button type="submit" className="w-full" disabled={mutation.isPending}>
                  {mutation.isPending && <Loader2 className="animate-spin" />}
                  Send reset link
                </Button>
              </form>
              <div className="border-t border-border pt-4 text-center">
                <Link to="/login" className="text-sm text-primary hover:underline">
                  ← Back to sign in
                </Link>
              </div>
            </CardContent>
          </>
        ) : (
          <CardContent className="py-4 text-center space-y-4">
            <CheckCircle2 className="mx-auto size-12 text-emerald-500" />
            <div className="space-y-1">
              <p className="font-semibold text-foreground">Email sent!</p>
              <p className="text-sm text-muted-foreground">Check your inbox for reset instructions.</p>
            </div>
            <p className="text-xs text-muted-foreground">Redirecting to sign in…</p>
            <div className="border-t border-border pt-4">
              <Link to="/login" className="text-sm text-primary hover:underline">
                ← Back to sign in
              </Link>
            </div>
          </CardContent>
        )}
      </Card>
    </AuthLayout>
  );
}
